display_content.json_block:
{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>스마트 팩토리 아키텍처</title>
<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&family=JetBrains+Mono:wght@400;600&family=Playfair+Display:wght@700;900&display=swap" rel="stylesheet">
<style>
  :root {
    --bg-deep: #0a0e1a;
    --bg-card: #111827;
    --bg-elevated: #1a2236;
    --border-subtle: rgba(99, 179, 237, 0.12);
    --border-glow: rgba(99, 179, 237, 0.3);
    --text-primary: #e8edf5;
    --text-secondary: #8b9dc3;
    --text-muted: #5a6a8a;
    --accent-blue: #63b3ed;
    --accent-cyan: #00d4aa;
    --accent-purple: #a78bfa;
    --accent-orange: #f6ad55;
    --accent-red: #fc8181;
    --accent-yellow: #fbd38d;
    --level-0: #2d6a4f;
    --level-1: #2563eb;
    --level-2: #7c3aed;
    --level-3: #db2777;
    --level-4: #ea580c;
    --glow-blue: 0 0 30px rgba(99, 179, 237, 0.15);
    --glow-cyan: 0 0 30px rgba(0, 212, 170, 0.15);
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    background: var(--bg-deep);
    color: var(--text-primary);
    font-family: 'Noto Sans KR', sans-serif;
    line-height: 1.7;
    overflow-x: hidden;
  }

  /* Subtle grid background */
  body::before {
    content: '';
    position: fixed;
    inset: 0;
    background:
      linear-gradient(rgba(99, 179, 237, 0.03) 1px, transparent 1px),
      linear-gradient(90deg, rgba(99, 179, 237, 0.03) 1px, transparent 1px);
    background-size: 60px 60px;
    pointer-events: none;
    z-index: 0;
  }

  .container {
    position: relative;
    z-index: 1;
    max-width: 1400px;
    margin: 0 auto;
    padding: 40px 30px 80px;
  }

  /* Header */
  .header {
    text-align: center;
    margin-bottom: 60px;
    animation: fadeInDown 0.8s ease-out;
  }

  .header-label {
    font-family: 'JetBrains Mono', monospace;
    font-size: 11px;
    letter-spacing: 4px;
    text-transform: uppercase;
    color: var(--accent-cyan);
    margin-bottom: 16px;
    opacity: 0.8;
  }

  .header h1 {
    font-family: 'Playfair Display', serif;
    font-size: clamp(32px, 5vw, 56px);
    font-weight: 900;
    background: linear-gradient(135deg, var(--accent-blue), var(--accent-cyan), var(--accent-purple));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin-bottom: 12px;
    line-height: 1.2;
  }

  .header p {
    font-size: 15px;
    color: var(--text-secondary);
    font-weight: 300;
    max-width: 600px;
    margin: 0 auto;
  }

  /* Tab Navigation */
  .tab-nav {
    display: flex;
    justify-content: center;
    gap: 8px;
    margin-bottom: 50px;
    animation: fadeInUp 0.8s ease-out 0.2s both;
  }

  .tab-btn {
    padding: 12px 28px;
    border: 1px solid var(--border-subtle);
    background: var(--bg-card);
    color: var(--text-secondary);
    font-family: 'Noto Sans KR', sans-serif;
    font-size: 14px;
    font-weight: 500;
    border-radius: 8px;
    cursor: pointer;
    transition: all 0.3s ease;
  }

  .tab-btn:hover {
    border-color: var(--border-glow);
    color: var(--text-primary);
  }

  .tab-btn.active {
    background: linear-gradient(135deg, rgba(99, 179, 237, 0.15), rgba(0, 212, 170, 0.1));
    border-color: var(--accent-blue);
    color: var(--accent-blue);
    box-shadow: var(--glow-blue);
  }

  .tab-content { display: none; }
  .tab-content.active { display: block; animation: fadeIn 0.5s ease-out; }

  /* ==================== */
  /* ISA-95 PYRAMID       */
  /* ==================== */

  .pyramid-section {
    max-width: 1000px;
    margin: 0 auto;
  }

  .pyramid-wrapper {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
  }

  .pyramid-level {
    position: relative;
    display: flex;
    align-items: center;
    gap: 20px;
    padding: 20px 30px;
    border-radius: 12px;
    border: 1px solid transparent;
    cursor: default;
    transition: all 0.4s ease;
    overflow: hidden;
  }

  .pyramid-level::before {
    content: '';
    position: absolute;
    inset: 0;
    border-radius: 12px;
    opacity: 0.06;
    transition: opacity 0.4s ease;
  }

  .pyramid-level:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 32px rgba(0,0,0,0.3);
  }

  .pyramid-level:hover::before { opacity: 0.12; }

  /* Widths creating pyramid shape */
  .level-4-row { width: 55%; }
  .level-3-row { width: 65%; }
  .level-2-row { width: 75%; }
  .level-1-row { width: 87%; }
  .level-0-row { width: 100%; }

  /* Level colors */
  .level-4-row { border-color: rgba(234, 88, 12, 0.3); background: rgba(234, 88, 12, 0.05); }
  .level-4-row::before { background: var(--level-4); }
  .level-3-row { border-color: rgba(219, 39, 119, 0.3); background: rgba(219, 39, 119, 0.05); }
  .level-3-row::before { background: var(--level-3); }
  .level-2-row { border-color: rgba(124, 58, 237, 0.3); background: rgba(124, 58, 237, 0.05); }
  .level-2-row::before { background: var(--level-2); }
  .level-1-row { border-color: rgba(37, 99, 235, 0.3); background: rgba(37, 99, 235, 0.05); }
  .level-1-row::before { background: var(--level-1); }
  .level-0-row { border-color: rgba(45, 106, 79, 0.3); background: rgba(45, 106, 79, 0.05); }
  .level-0-row::before { background: var(--level-0); }

  .level-badge {
    flex-shrink: 0;
    width: 52px;
    height: 52px;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-family: 'JetBrains Mono', monospace;
    font-size: 13px;
    font-weight: 600;
    color: white;
  }

  .level-4-row .level-badge { background: linear-gradient(135deg, #ea580c, #f97316); }
  .level-3-row .level-badge { background: linear-gradient(135deg, #db2777, #ec4899); }
  .level-2-row .level-badge { background: linear-gradient(135deg, #7c3aed, #8b5cf6); }
  .level-1-row .level-badge { background: linear-gradient(135deg, #2563eb, #3b82f6); }
  .level-0-row .level-badge { background: linear-gradient(135deg, #2d6a4f, #40916c); }

  .level-info { flex: 1; }

  .level-title {
    font-size: 16px;
    font-weight: 700;
    margin-bottom: 4px;
  }

  .level-subtitle {
    font-size: 12px;
    color: var(--text-secondary);
    font-weight: 300;
    margin-bottom: 8px;
  }

  .level-tags {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
  }

  .tag {
    font-family: 'JetBrains Mono', monospace;
    font-size: 10px;
    padding: 3px 10px;
    border-radius: 20px;
    background: rgba(255,255,255,0.06);
    color: var(--text-secondary);
    border: 1px solid rgba(255,255,255,0.08);
    white-space: nowrap;
  }

  .level-time {
    flex-shrink: 0;
    text-align: right;
    font-family: 'JetBrains Mono', monospace;
    font-size: 11px;
    color: var(--text-muted);
  }

  .level-time .time-value {
    font-size: 18px;
    font-weight: 600;
    color: var(--text-secondary);
    display: block;
  }

  /* Connectors between levels */
  .connector {
    width: 2px;
    height: 20px;
    background: linear-gradient(to bottom, var(--border-glow), transparent);
    position: relative;
  }

  .connector::after {
    content: '▼';
    position: absolute;
    bottom: -8px;
    left: 50%;
    transform: translateX(-50%);
    font-size: 8px;
    color: var(--accent-blue);
    opacity: 0.5;
  }

  /* Side annotations */
  .pyramid-annotations {
    display: flex;
    justify-content: space-between;
    margin-top: 30px;
    gap: 20px;
  }

  .annotation-box {
    flex: 1;
    padding: 20px;
    border-radius: 12px;
    background: var(--bg-card);
    border: 1px solid var(--border-subtle);
  }

  .annotation-box h4 {
    font-size: 13px;
    font-weight: 700;
    margin-bottom: 8px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .annotation-box p {
    font-size: 12px;
    color: var(--text-secondary);
    line-height: 1.8;
  }

  .zone-indicator {
    display: inline-block;
    width: 10px;
    height: 10px;
    border-radius: 3px;
  }

  /* ==================== */
  /* HOUSE-PILLAR MODEL   */
  /* ==================== */

  .house-section {
    max-width: 1100px;
    margin: 0 auto;
  }

  .house-container {
    display: flex;
    flex-direction: column;
    gap: 0;
  }

  /* Roof */
  .house-roof {
    position: relative;
    text-align: center;
    padding: 32px 40px;
    background: linear-gradient(135deg, rgba(99, 179, 237, 0.1), rgba(0, 212, 170, 0.08));
    border: 1px solid var(--accent-cyan);
    border-radius: 16px 16px 0 0;
    clip-path: polygon(10% 100%, 0% 30%, 50% 0%, 100% 30%, 90% 100%);
    min-height: 160px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding-top: 50px;
  }

  .house-roof h3 {
    font-family: 'Playfair Display', serif;
    font-size: 22px;
    font-weight: 700;
    background: linear-gradient(135deg, var(--accent-cyan), var(--accent-blue));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  .house-roof .roof-sub {
    font-size: 12px;
    color: var(--text-secondary);
    margin-top: 4px;
  }

  /* Top floor (Strategy) */
  .house-top {
    padding: 24px 30px;
    background: var(--bg-elevated);
    border-left: 1px solid var(--border-subtle);
    border-right: 1px solid var(--border-subtle);
    text-align: center;
  }

  .house-top h4 {
    font-size: 14px;
    font-weight: 700;
    color: var(--accent-orange);
    margin-bottom: 10px;
  }

  .house-top-items {
    display: flex;
    justify-content: center;
    gap: 12px;
    flex-wrap: wrap;
  }

  .top-item {
    padding: 8px 18px;
    background: rgba(246, 173, 85, 0.08);
    border: 1px solid rgba(246, 173, 85, 0.2);
    border-radius: 8px;
    font-size: 12px;
    color: var(--accent-orange);
    font-weight: 500;
  }

  /* Pillars section */
  .house-pillars-area {
    display: flex;
    border-left: 1px solid var(--border-subtle);
    border-right: 1px solid var(--border-subtle);
    min-height: 400px;
  }

  .pillar {
    flex: 1;
    padding: 24px 16px;
    display: flex;
    flex-direction: column;
    align-items: center;
    border-right: 1px solid var(--border-subtle);
    position: relative;
    transition: all 0.4s ease;
  }

  .pillar:last-child { border-right: none; }

  .pillar:hover {
    background: rgba(255,255,255,0.02);
  }

  .pillar-icon {
    width: 48px;
    height: 48px;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 22px;
    margin-bottom: 14px;
    position: relative;
  }

  .pillar-icon::after {
    content: '';
    position: absolute;
    inset: -3px;
    border-radius: 14px;
    border: 1px dashed rgba(255,255,255,0.1);
  }

  .pillar:nth-child(1) .pillar-icon { background: rgba(37, 99, 235, 0.15); }
  .pillar:nth-child(2) .pillar-icon { background: rgba(124, 58, 237, 0.15); }
  .pillar:nth-child(3) .pillar-icon { background: rgba(0, 212, 170, 0.15); }
  .pillar:nth-child(4) .pillar-icon { background: rgba(219, 39, 119, 0.15); }
  .pillar:nth-child(5) .pillar-icon { background: rgba(246, 173, 85, 0.15); }

  .pillar-title {
    font-size: 13px;
    font-weight: 700;
    text-align: center;
    margin-bottom: 6px;
    line-height: 1.4;
  }

  .pillar:nth-child(1) .pillar-title { color: var(--accent-blue); }
  .pillar:nth-child(2) .pillar-title { color: var(--accent-purple); }
  .pillar:nth-child(3) .pillar-title { color: var(--accent-cyan); }
  .pillar:nth-child(4) .pillar-title { color: var(--accent-red); }
  .pillar:nth-child(5) .pillar-title { color: var(--accent-orange); }

  .pillar-desc {
    font-size: 11px;
    color: var(--text-muted);
    text-align: center;
    margin-bottom: 16px;
  }

  .pillar-items {
    display: flex;
    flex-direction: column;
    gap: 6px;
    width: 100%;
  }

  .pillar-item {
    padding: 8px 12px;
    background: rgba(255,255,255,0.03);
    border: 1px solid rgba(255,255,255,0.06);
    border-radius: 6px;
    font-size: 11px;
    color: var(--text-secondary);
    text-align: center;
    transition: all 0.3s ease;
  }

  .pillar-item:hover {
    background: rgba(255,255,255,0.06);
    border-color: rgba(255,255,255,0.12);
  }

  .pillar-item .item-label {
    font-weight: 600;
    color: var(--text-primary);
    display: block;
    margin-bottom: 2px;
  }

  /* Cross-cutting bar */
  .cross-bar {
    padding: 16px 24px;
    background: linear-gradient(90deg, rgba(167, 139, 250, 0.08), rgba(99, 179, 237, 0.08), rgba(0, 212, 170, 0.08));
    border: 1px solid var(--border-subtle);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 30px;
    flex-wrap: wrap;
  }

  .cross-bar-label {
    font-size: 12px;
    font-weight: 700;
    color: var(--accent-purple);
    white-space: nowrap;
  }

  .cross-bar-items {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    justify-content: center;
  }

  .cross-item {
    font-size: 11px;
    padding: 4px 12px;
    background: rgba(167, 139, 250, 0.1);
    border: 1px solid rgba(167, 139, 250, 0.2);
    border-radius: 20px;
    color: var(--accent-purple);
    white-space: nowrap;
  }

  /* Foundation */
  .house-foundation {
    padding: 24px 30px;
    background: linear-gradient(135deg, rgba(45, 106, 79, 0.1), rgba(37, 99, 235, 0.08));
    border: 1px solid rgba(45, 106, 79, 0.3);
    border-radius: 0 0 16px 16px;
    text-align: center;
  }

  .house-foundation h4 {
    font-size: 14px;
    font-weight: 700;
    color: var(--level-0);
    margin-bottom: 10px;
  }

  .foundation-items {
    display: flex;
    justify-content: center;
    gap: 12px;
    flex-wrap: wrap;
  }

  .foundation-item {
    padding: 8px 16px;
    background: rgba(45, 106, 79, 0.08);
    border: 1px solid rgba(45, 106, 79, 0.2);
    border-radius: 8px;
    font-size: 12px;
    color: var(--text-secondary);
  }

  .foundation-item strong {
    color: #40916c;
  }

  /* PLC Highlight */
  .plc-highlight {
    margin-top: 40px;
    padding: 28px 32px;
    background: var(--bg-card);
    border: 1px solid rgba(37, 99, 235, 0.3);
    border-radius: 14px;
    position: relative;
    overflow: hidden;
  }

  .plc-highlight::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 4px;
    height: 100%;
    background: linear-gradient(to bottom, var(--accent-blue), var(--accent-cyan));
  }

  .plc-highlight h4 {
    font-size: 15px;
    font-weight: 700;
    color: var(--accent-blue);
    margin-bottom: 10px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .plc-highlight p {
    font-size: 13px;
    color: var(--text-secondary);
    line-height: 1.9;
  }

  .plc-highlight .highlight-tag {
    display: inline-block;
    padding: 2px 8px;
    background: rgba(37, 99, 235, 0.12);
    border-radius: 4px;
    font-family: 'JetBrains Mono', monospace;
    font-size: 11px;
    color: var(--accent-blue);
  }

  /* Data flow line decoration */
  .data-flow-label {
    text-align: center;
    padding: 10px;
    font-family: 'JetBrains Mono', monospace;
    font-size: 10px;
    color: var(--text-muted);
    letter-spacing: 2px;
  }

  .data-flow-label span {
    opacity: 0.4;
  }

  /* Animations */
  @keyframes fadeInDown {
    from { opacity: 0; transform: translateY(-20px); }
    to { opacity: 1; transform: translateY(0); }
  }

  @keyframes fadeInUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
  }

  @keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
  }

  .pyramid-level {
    animation: fadeInUp 0.6s ease-out both;
  }
  .level-4-row { animation-delay: 0.1s; }
  .level-3-row { animation-delay: 0.2s; }
  .level-2-row { animation-delay: 0.3s; }
  .level-1-row { animation-delay: 0.4s; }
  .level-0-row { animation-delay: 0.5s; }

  /* Responsive */
  @media (max-width: 768px) {
    .container { padding: 20px 16px 60px; }
    .pyramid-level { padding: 14px 16px; gap: 12px; }
    .level-4-row, .level-3-row, .level-2-row, .level-1-row, .level-0-row { width: 100%; }
    .level-time { display: none; }
    .level-badge { width: 40px; height: 40px; font-size: 11px; }
    .house-pillars-area { flex-direction: column; }
    .pillar { border-right: none; border-bottom: 1px solid var(--border-subtle); padding: 20px; }
    .pillar:last-child { border-bottom: none; }
    .pyramid-annotations { flex-direction: column; }
    .house-roof { clip-path: none; border-radius: 16px 16px 0 0; min-height: auto; padding: 24px; }
    .tab-nav { flex-direction: column; align-items: stretch; }
  }
</style>
</head>
<body>

<div class="container">
  <!-- Header -->
  <div class="header">
    <div class="header-label">Smart Factory Architecture Reference</div>
    <h1>스마트 팩토리 아키텍처</h1>
    <p>ISA-95 피라미드 모델과 하우스-필라 모델로 보는<br>제조 시스템의 계층 구조와 기술 생태계</p>
  </div>

  <!-- Tab Navigation -->
  <div class="tab-nav">
    <button class="tab-btn active" onclick="switchTab('pyramid')">▲ ISA-95 피라미드 모델</button>
    <button class="tab-btn" onclick="switchTab('house')">🏛 하우스-필라 모델</button>
  </div>

  <!-- ===================== -->
  <!-- TAB 1: ISA-95 PYRAMID -->
  <!-- ===================== -->
  <div id="tab-pyramid" class="tab-content active">
    <div class="pyramid-section">
      <div class="pyramid-wrapper">

        <!-- Level 4: Business Planning -->
        <div class="pyramid-level level-4-row">
          <div class="level-badge">L4</div>
          <div class="level-info">
            <div class="level-title">경영 계획 (Business Planning)</div>
            <div class="level-subtitle">전사 경영 전략 · 재무 · 수요 계획 · 공급망 최적화</div>
            <div class="level-tags">
              <span class="tag">ERP</span>
              <span class="tag">SCM</span>
              <span class="tag">PLM</span>
              <span class="tag">BI / Analytics</span>
            </div>
          </div>
          <div class="level-time">
            응답<br>
            <span class="time-value">일~월</span>
          </div>
        </div>

        <div class="connector"></div>

        <!-- Level 3: Manufacturing Operations -->
        <div class="pyramid-level level-3-row">
          <div class="level-badge">L3</div>
          <div class="level-info">
            <div class="level-title">제조 운영 관리 (Manufacturing Operations)</div>
            <div class="level-subtitle">생산 스케줄링 · 품질 관리 · 재고 추적 · 설비 관리</div>
            <div class="level-tags">
              <span class="tag">MES</span>
              <span class="tag">MOM</span>
              <span class="tag">QMS</span>
              <span class="tag">WMS</span>
              <span class="tag">APS</span>
            </div>
          </div>
          <div class="level-time">
            응답<br>
            <span class="time-value">분~시간</span>
          </div>
        </div>

        <div class="connector"></div>

        <!-- Level 2: Monitoring & Supervisory -->
        <div class="pyramid-level level-2-row">
          <div class="level-badge">L2</div>
          <div class="level-info">
            <div class="level-title">감시·감독 제어 (Monitoring & Supervisory)</div>
            <div class="level-subtitle">실시간 모니터링 · 알람 관리 · 데이터 수집 · HMI</div>
            <div class="level-tags">
              <span class="tag">SCADA</span>
