  .tech-chip .chip-icon { font-size: 13px; }

  .chip-robot { color: var(--robot); background: var(--robot-bg); border-color: var(--robot-border); }
  .chip-sf { color: var(--sf); background: var(--sf-bg); border-color: var(--sf-border); }
  .chip-data { color: var(--data); background: var(--data-bg); border-color: var(--data-border); }
  .chip-infra { color: var(--infra); background: var(--infra-bg); border-color: var(--infra-border); }
  .chip-human { color: var(--human); background: var(--human-bg); border-color: var(--human-border); }

  .chip-core {
    font-weight: 700;
    box-shadow: 0 0 12px rgba(255,255,255,0.03);
  }

  /* ======================== */
  /* VIEW 2: DOMAIN COLUMNS   */
  /* ======================== */

  .domain-grid {
    display: grid;
    grid-template-columns: repeat(5, 1fr);
    gap: 10px;
  }

  .domain-col {
    border-radius: 12px;
    overflow: hidden;
    border: 1px solid var(--border);
    transition: all 0.4s;
  }

  .domain-col:hover {
    border-color: var(--border-active);
    transform: translateY(-3px);
    box-shadow: 0 12px 40px rgba(0,0,0,0.3);
  }

  .domain-header {
    padding: 20px 16px;
    text-align: center;
    border-bottom: 1px solid var(--border);
  }

  .domain-header .dh-icon {
    font-size: 28px;
    margin-bottom: 8px;
  }

  .domain-header h3 {
    font-size: 14px;
    font-weight: 700;
    margin-bottom: 4px;
  }

  .domain-header .dh-sub {
    font-size: 11px;
    color: var(--text-3);
    font-weight: 300;
  }

  .domain-col:nth-child(1) .domain-header { background: var(--robot-bg); }
  .domain-col:nth-child(1) .domain-header h3 { color: var(--robot); }
  .domain-col:nth-child(2) .domain-header { background: var(--sf-bg); }
  .domain-col:nth-child(2) .domain-header h3 { color: var(--sf); }
  .domain-col:nth-child(3) .domain-header { background: var(--data-bg); }
  .domain-col:nth-child(3) .domain-header h3 { color: var(--data); }
  .domain-col:nth-child(4) .domain-header { background: var(--infra-bg); }
  .domain-col:nth-child(4) .domain-header h3 { color: var(--infra); }
  .domain-col:nth-child(5) .domain-header { background: var(--human-bg); }
  .domain-col:nth-child(5) .domain-header h3 { color: var(--human); }

  .domain-body {
    background: var(--bg-card);
    padding: 12px;
  }

  .domain-group {
    margin-bottom: 12px;
  }

  .domain-group:last-child { margin-bottom: 0; }

  .dg-label {
    font-family: 'JetBrains Mono', monospace;
    font-size: 9px;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    color: var(--text-3);
    padding: 4px 0;
    margin-bottom: 6px;
    border-bottom: 1px solid var(--border);
  }

  .dg-items {
    display: flex;
    flex-direction: column;
    gap: 4px;
  }

  .dg-item {
    padding: 8px 10px;
    background: rgba(255,255,255,0.02);
    border: 1px solid rgba(255,255,255,0.04);
    border-radius: 6px;
    font-size: 11px;
    line-height: 1.5;
    transition: all 0.3s;
  }

  .dg-item:hover {
    background: rgba(255,255,255,0.04);
    border-color: rgba(255,255,255,0.08);
  }

  .dg-item strong {
    display: block;
    font-size: 11.5px;
    margin-bottom: 1px;
  }

  .dg-item span {
    color: var(--text-3);
    font-size: 10px;
  }

  .domain-col:nth-child(1) .dg-item strong { color: var(--robot); }
  .domain-col:nth-child(2) .dg-item strong { color: var(--sf); }
  .domain-col:nth-child(3) .dg-item strong { color: var(--data); }
  .domain-col:nth-child(4) .dg-item strong { color: var(--infra); }
  .domain-col:nth-child(5) .dg-item strong { color: var(--human); }

  /* ======================== */
  /* VIEW 3: INTEGRATION MAP  */
  /* ======================== */

  .integration-section {
    max-width: 1000px;
    margin: 0 auto;
  }

  .scenario-card {
    padding: 28px 32px;
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 14px;
    margin-bottom: 14px;
    transition: all 0.3s;
  }

  .scenario-card:hover {
    border-color: var(--border-active);
    transform: translateX(3px);
  }

  .sc-header {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 16px;
  }

  .sc-num {
    width: 36px;
    height: 36px;
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-family: 'JetBrains Mono', monospace;
    font-size: 14px;
    font-weight: 600;
    color: white;
    flex-shrink: 0;
  }

  .sc-header h3 {
    font-size: 16px;
    font-weight: 700;
  }

  .sc-header .sc-tag {
    font-size: 11px;
    padding: 3px 10px;
    border-radius: 20px;
    font-weight: 500;
    margin-left: auto;
    white-space: nowrap;
  }

  .sc-flow {
    display: flex;
    align-items: center;
    gap: 8px;
    flex-wrap: wrap;
    margin-bottom: 14px;
  }

  .flow-node {
    padding: 8px 14px;
    border-radius: 8px;
    font-size: 11.5px;
    font-weight: 600;
    border: 1px solid;
    white-space: nowrap;
  }

  .flow-arrow {
    font-family: 'JetBrains Mono', monospace;
    font-size: 14px;
    color: var(--text-3);
  }

  .sc-desc {
    font-size: 13px;
    color: var(--text-2);
    line-height: 1.9;
    padding-left: 50px;
  }

  .sc-desc .highlight {
    font-weight: 600;
    color: var(--text-1);
  }

  /* Scenario colors */
  .scenario-card:nth-child(1) .sc-num { background: linear-gradient(135deg, var(--robot), #60a5fa); }
  .scenario-card:nth-child(1) .sc-tag { color: var(--robot); background: var(--robot-bg); }
  .scenario-card:nth-child(2) .sc-num { background: linear-gradient(135deg, var(--sf), #34d399); }
  .scenario-card:nth-child(2) .sc-tag { color: var(--sf); background: var(--sf-bg); }
  .scenario-card:nth-child(3) .sc-num { background: linear-gradient(135deg, var(--data), #c4b5fd); }
  .scenario-card:nth-child(3) .sc-tag { color: var(--data); background: var(--data-bg); }
  .scenario-card:nth-child(4) .sc-num { background: linear-gradient(135deg, var(--infra), #fbbf24); }
  .scenario-card:nth-child(4) .sc-tag { color: var(--infra); background: var(--infra-bg); }
  .scenario-card:nth-child(5) .sc-num { background: linear-gradient(135deg, var(--human), #f472b6); }
  .scenario-card:nth-child(5) .sc-tag { color: var(--human); background: var(--human-bg); }

  /* Bottom insight */
  .insight-box {
    margin-top: 40px;
    padding: 28px 32px;
    background: var(--bg-card);
    border: 1px solid var(--sf-border);
    border-radius: 14px;
    position: relative;
    overflow: hidden;
  }

  .insight-box::before {
    content: '';
    position: absolute;
    top: 0; left: 0;
    width: 4px; height: 100%;
    background: linear-gradient(to bottom, var(--robot), var(--sf), var(--data));
  }

  .insight-box h4 {
    font-size: 15px;
    font-weight: 700;
    color: var(--sf);
    margin-bottom: 12px;
  }

  .insight-box p {
    font-size: 13px;
    color: var(--text-2);
    line-height: 2;
  }

  .insight-box .hl {
    font-family: 'JetBrains Mono', monospace;
    font-size: 11px;
    padding: 2px 8px;
    border-radius: 4px;
  }

  .hl-robot { background: var(--robot-bg); color: var(--robot); }
  .hl-sf { background: var(--sf-bg); color: var(--sf); }
  .hl-data { background: var(--data-bg); color: var(--data); }

  /* Responsive */
  @media (max-width: 900px) {
    .domain-grid { grid-template-columns: 1fr 1fr; }
    .domain-col:nth-child(5) { grid-column: span 2; }
    .layer-row { grid-template-columns: 110px 1fr; }
    .sc-desc { padding-left: 0; }
  }

  @media (max-width: 600px) {
    .domain-grid { grid-template-columns: 1fr; }
    .domain-col:nth-child(5) { grid-column: span 1; }
    .layer-row { grid-template-columns: 1fr; }
    .layer-label { border-right: none; border-bottom: 1px solid var(--border); }
    .legend { gap: 10px; }
    .sc-flow { gap: 4px; }
    .flow-node { font-size: 10px; padding: 5px 8px; }
    .view-toggle { flex-direction: column; align-items: stretch; }
  }
</style>
</head>
<body>

<div class="wrap">
  <!-- Header -->
  <div class="hdr">
    <div class="hdr-eyebrow">Implementation Technology Map</div>
    <h1>스마트 팩토리 <em>요소기술 구현 맵</em></h1>
    <p>아키텍처 계층을 로봇 · 스마트 팩토리 솔루션 · 데이터 솔루션 · 인프라 · 인재 역량의 5개 요소기술 도메인으로 매핑</p>
  </div>

  <!-- Legend -->
