    <div class="legend-item"><div class="legend-dot" style="background:var(--robot);"></div><span style="color:var(--robot);">로봇 솔루션</span></div>
    <div class="legend-item"><div class="legend-dot" style="background:var(--sf);"></div><span style="color:var(--sf);">스마트팩토리 솔루션</span></div>
    <div class="legend-item"><div class="legend-dot" style="background:var(--data);"></div><span style="color:var(--data);">데이터 솔루션</span></div>
    <div class="legend-item"><div class="legend-dot" style="background:var(--infra);"></div><span style="color:var(--infra);">인프라 · 네트워크</span></div>
    <div class="legend-item"><div class="legend-dot" style="background:var(--human);"></div><span style="color:var(--human);">인재 · 역량</span></div>
  </div>

  <!-- View Toggle -->
  <div class="view-toggle">
    <button class="view-btn active" onclick="switchView('v1')">📊 계층별 기술 매핑</button>
    <button class="view-btn" onclick="switchView('v2')">🏛 도메인별 기술 스택</button>
    <button class="view-btn" onclick="switchView('v3')">🔗 통합 시나리오</button>
  </div>

  <!-- ======================== -->
  <!-- VIEW 1: LAYER MAP        -->
  <!-- ======================== -->
  <div id="v1" class="view-panel active">
    <div class="layer-map">

