          <div class="tech-chip chip-infra"><span class="chip-icon">📡</span>MQTT Broker</div>
          <div class="tech-chip chip-robot"><span class="chip-icon">🤖</span>로봇 모니터링</div>
          <div class="tech-chip chip-data"><span class="chip-icon">🧠</span>Edge AI 추론</div>
        </div>
      </div>

      <!-- L1 Control -->
      <div class="layer-row">
        <div class="layer-label">
          <div class="ll-level">LEVEL 1</div>
          <div class="ll-name" style="color:var(--robot);">직접 제어</div>
