      <div class="layer-row">
        <div class="layer-label">
          <div class="ll-level">LEVEL 0</div>
          <div class="ll-name">물리 프로세스</div>
          <div class="ll-time">⏱ μs~ms</div>
        </div>
        <div class="layer-techs">
          <div class="tech-chip chip-infra"><span class="chip-icon">🌡️</span>온도/압력/유량 센서</div>
          <div class="tech-chip chip-infra"><span class="chip-icon">📷</span>비전 카메라</div>
          <div class="tech-chip chip-infra"><span class="chip-icon">📏</span>레이저 변위 센서</div>
